using Effekseer;using System.Collections;using System.Collections.Generic;using UnityEngine;public class SampleScriptSlash: MonoBehaviour{// Start is called before the first frame update    void Start(){        EffekseerEffectAsset effect = Resources.Load<EffekseerEffectAsset>("Premium/Slash/Slash");        EffekseerHandle handle = EffekseerSystem.PlayEffect(effect, transform.position);        StartCoroutine(play(effect));    }    IEnumerator play(EffekseerEffectAsset effect)    {        while (true)        {            EffekseerSystem.PlayEffect(effect, transform.position);            yield return new WaitForSeconds(1);        }    }}            